1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	const DEDUCTIBLE = 100;
24	const CAP_MULTIPLIER = 2;
25	
26	interface Item {
27	  type: string;
28	  cursed?: boolean;
29	  enchantment?: number;
30	  material?: string;
31	}
32	
33	interface Damage {
34	  itemType: string;
35	  amount: number;
36	}
37	
38	interface Incident {
39	  cause?: string;
40	  damages: Damage[];
41	}
42	
43	interface Step {
44	  op: string;
45	  items?: Item[];
46	  policy?: number;
47	  incident?: Incident;
48	}
49	
50	interface Customer {
51	  yearsWithMHPCO: number;
52	}
53	
54	interface Scenario {
55	  customer: Customer;
56	  steps: Step[];
57	}
58	
59	const BLOCK_SIZE = 3;
60	const BLOCK_PREMIUM = 60;
61	const CURSE_SURCHARGE_PERCENT = 50;
62	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
63	const HIGH_ENCHANTMENT_THRESHOLD = 5;
64	const LOYALTY_DISCOUNT_PERCENT = 20;
65	const LOYALTY_THRESHOLD_YEARS = 2;
66	const FOLLOWUP_DISCOUNT_PERCENT = 15;
67	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const percentOf = (amount: number, percent: number): number =>
72	  (amount * percent) / PERCENT_BASE;
73	
74	const percentIf = (condition: boolean, base: number, percent: number): number =>
75	  condition ? percentOf(base, percent) : 0;
76	
77	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
78	
79	const itemSurcharges = (item: Item): number => {
80	  const base = itemBasePremium(item);
81	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
82	  const highEnchantment = percentIf(
83	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
84	    base,
85	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
86	  );
87	  return curse + highEnchantment;
88	};
89	
90	const sumItemBases = (items: Item[]): number =>
91	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
92	
93	const sumSurcharges = (items: Item[]): number =>
94	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
95	
96	const partitionByType = (items: Item[]): Item[][] => {
97	  const groups: Record<string, Item[]> = {};
98	  items.forEach((item) => (groups[item.type] ??= []).push(item));
99	  return Object.values(groups);
100	};
101	
102	const isComponentBlock = (group: Item[]): boolean =>
103	  group.length === BLOCK_SIZE && isComponent(group[0]);
104	
105	const priceGroup = (group: Item[]): number =>
106	  isComponentBlock(group) ? BLOCK_PREMIUM : sumItemBases(group);
107	
108	const sumBasePremiums = (items: Item[]): number =>
109	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
110	
111	const isLoyalCustomer = (customer: Customer): boolean =>
112	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
113	
114	const applyPolicyModifiers = (
115	  base: number,
116	  customer: Customer,
117	  isFollowUp: boolean,
118	): number => {
119	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
120	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
121	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
122	  return base + firstInsurance - loyalty - followUp;
123	};
124	
125	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
126	  const policyBase = sumBasePremiums(items);
127	  const surcharges = sumSurcharges(items);
128	  return Math.ceil(applyPolicyModifiers(policyBase, customer, isFollowUp) + surcharges) + PROCESSING_FEE;
129	};
130	
131	const policyInsuranceSum = (items: Item[]): number =>
132	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
133	
134	const damagePayout = (damage: Damage): number =>
135	  Math.max(0, damage.amount - DEDUCTIBLE);
136	
137	const processClaim = (
138	  step: Step,
139	  policyItems: Item[],
140	): { payout: number; remainingCap: number } => {
141	  const damages = step.incident?.damages ?? [];
142	  const payout = damages.reduce((sum, d) => sum + damagePayout(d), 0);
143	  const cap = policyInsuranceSum(policyItems) * CAP_MULTIPLIER;
144	  return { payout, remainingCap: cap - payout };
145	};
146	
147	const isQuote = (step: Step): boolean => step.op === "quote";
148	
149	const precedingQuoteCount = (steps: Step[], index: number): number =>
150	  steps.slice(0, index).filter(isQuote).length;
151	
152	const executeStep = (
153	  step: Step,
154	  customer: Customer,
155	  steps: Step[],
156	  index: number,
157	): { premium: number } | { payout: number; remainingCap: number } => {
158	  if (step.op === "claim") {
159	    const policyStep = steps[step.policy ?? 0];
160	    return processClaim(step, policyStep.items ?? []);
161	  }
162	  const isFollowUp = isQuote(step) && precedingQuoteCount(steps, index) > 0;
163	  return { premium: quotePremium(step.items ?? [], customer, isFollowUp) };
164	};
165	
166	export const runScenario = (input: unknown): { results: unknown[] } => {
167	  const scenario = input as Scenario;
168	  return {
169	    results: scenario.steps.map((step, index) =>
170	      executeStep(step, scenario.customer, scenario.steps, index),
171	    ),
172	  };
173	};
