const isQuote = (step: Step): boolean => step.op === "quote";

const hasPriorQuote = (steps: Step[], index: number): boolean =>
  steps.slice(0, index).some(isQuote);

const quoteStep = (
  step: Step,
  customer: Customer,
  isFollowUp: boolean,
): { premium: number } => ({
  premium: quotePremium(step.items ?? [], customer, isFollowUp),
});

const claimStep = (
  step: Step,
  steps: Step[],
): { payout: number; remainingCap: number } =>
  processClaim(step, steps[step.policy ?? 0].items ?? []);

const executeStep = (
  step: Step,
  customer: Customer,
  steps: Step[],
  index: number,
): { premium: number } | { payout: number; remainingCap: number } =>
  step.op === "claim"
    ? claimStep(step, steps)
    : quoteStep(step, customer, hasPriorQuote(steps, index));
